const fs = require('fs');
const path = require('path');

const SQL_DIR = path.join(__dirname, '../../../sql/dispatcher');

function loadSql(fileName) {
    const filePath = path.join(SQL_DIR, fileName);
    if (!fs.existsSync(filePath)) {
        throw new Error(`No se encontro SQL del dispatcher: ${filePath}`);
    }
    return fs.readFileSync(filePath, 'utf8');
}

const COUNT_ACTIVE_CALLS = loadSql('count_active_calls.sql');
const SELECT_PENDING_FOR_LOCK = loadSql('select_pending_for_lock.sql');
const MARK_EN_CURSO = loadSql('mark_en_curso.sql');
const FETCH_DISPATCH_CONTEXT = loadSql('fetch_dispatch_context.sql');
const UPDATE_CALL_STATE = loadSql('update_call_state.sql');

module.exports = {
    COUNT_ACTIVE_CALLS,
    SELECT_PENDING_FOR_LOCK,
    MARK_EN_CURSO,
    FETCH_DISPATCH_CONTEXT,
    UPDATE_CALL_STATE,
};

const fs = require('fs');
const path = require('path');

const SQL_DIR = path.join(__dirname, '../../../sql/dispatcher');

function loadSql(fileName) {
    const filePath = path.join(SQL_DIR, fileName);
    if (!fs.existsSync(filePath)) {
        throw new Error(`No se encontro SQL del dispatcher: ${filePath}`);
    }
    return fs.readFileSync(filePath, 'utf8');
}

const COUNT_ACTIVE_CALLS = loadSql('count_active_calls.sql');
const SELECT_PENDING_FOR_LOCK = loadSql('select_pending_for_lock.sql');
const MARK_EN_CURSO = loadSql('mark_en_curso.sql');
const FETCH_DISPATCH_CONTEXT = loadSql('fetch_dispatch_context.sql');
const FETCH_CANDIDATE_DISPATCH_CONTEXT = loadSql('fetch_candidate_dispatch_context.sql');
const UPDATE_CALL_STATE = loadSql('update_call_state.sql');

module.exports = {
    COUNT_ACTIVE_CALLS,
    SELECT_PENDING_FOR_LOCK,
    MARK_EN_CURSO,
    FETCH_DISPATCH_CONTEXT,
    FETCH_CANDIDATE_DISPATCH_CONTEXT,
    UPDATE_CALL_STATE,
};

const { getClient, query } = require('../../config/postgres');
const {
    COUNT_ACTIVE_CALLS,
    SELECT_PENDING_FOR_LOCK,
    MARK_EN_CURSO,
    FETCH_DISPATCH_CONTEXT,
    UPDATE_CALL_STATE,
} = require('./queries');

async function countActiveCalls() {
    const res = await query(COUNT_ACTIVE_CALLS);
    return res.rows[0] ? res.rows[0].cnt : 0;
}

async function lockNextPendingCalls(limit) {
    const client = await getClient();

    try {
        await client.query('BEGIN');

        const pending = await client.query(SELECT_PENDING_FOR_LOCK, [limit]);
        if (!pending.rowCount) {
            await client.query('COMMIT');
            return [];
        }

        const ids = pending.rows.map((row) => row.id);
        const updated = await client.query(MARK_EN_CURSO, [ids]);

        await client.query('COMMIT');
        return updated.rows;
    } catch (err) {
        try {
            await client.query('ROLLBACK');
        } catch (_) {
            // ignore rollback secondary error
        }
        throw err;
    } finally {
        client.release();
    }
}

async function getDispatchContext(queueIds) {
    if (!queueIds || queueIds.length === 0) {
        return [];
    }

    const res = await query(FETCH_DISPATCH_CONTEXT, [queueIds]);
    return res.rows;
}

async function setCallState(queueId, state) {
    await query(UPDATE_CALL_STATE, [queueId, state]);
}

module.exports = {
    countActiveCalls,
    lockNextPendingCalls,
    getDispatchContext,
    setCallState,
};

const { getClient, query } = require('../../config/postgres');
const {
    COUNT_ACTIVE_CALLS,
    SELECT_PENDING_FOR_LOCK,
    MARK_EN_CURSO,
    FETCH_DISPATCH_CONTEXT,
    FETCH_CANDIDATE_DISPATCH_CONTEXT,
    UPDATE_CALL_STATE,
} = require('./queries');

async function countActiveCalls() {
    const res = await query(COUNT_ACTIVE_CALLS);
    return res.rows[0] ? res.rows[0].cnt : 0;
}

async function lockNextPendingCalls(limit) {
    const client = await getClient();

    try {
        await client.query('BEGIN');

        const pending = await client.query(SELECT_PENDING_FOR_LOCK, [limit]);
        if (!pending.rowCount) {
            await client.query('COMMIT');
            return [];
        }

        const ids = pending.rows.map((row) => row.id);
        const updated = await client.query(MARK_EN_CURSO, [ids]);

        await client.query('COMMIT');
        return updated.rows;
    } catch (err) {
        try {
            await client.query('ROLLBACK');
        } catch (_) {
            // ignore rollback secondary error
        }
        throw err;
    } finally {
        client.release();
    }
}

async function getDispatchContext(queueIds) {
    if (!queueIds || queueIds.length === 0) {
        return [];
    }

    const res = await query(FETCH_DISPATCH_CONTEXT, [queueIds]);
    return res.rows;
}

async function getDispatchContextByCandidateId(candidateId) {
    const res = await query(FETCH_CANDIDATE_DISPATCH_CONTEXT, [candidateId]);
    return res.rowCount ? res.rows[0] : null;
}

async function setCallState(queueId, state) {
    await query(UPDATE_CALL_STATE, [queueId, state]);
}

module.exports = {
    countActiveCalls,
    lockNextPendingCalls,
    getDispatchContext,
    getDispatchContextByCandidateId,
    setCallState,
};
